var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"한 가지 묻고 싶은 게 있어, 파벨라.","JPN":"1つ聞きたいことがある、ファヴェーラ。","ENG":"There’s one thing I want to ask you, Fabella.","TWN":"帕貝拉，我有件事想問你。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"동료 다니엘이 나에게 말해줬어.","JPN":"同僚のダニエルが俺に言ったんだ。","ENG":"Daniel told me...","TWN":"丹尼爾跟我說，"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이 프레데리카와 같은 오퍼레이터 동기이자 아주 친한 친구였다고 말이야.","JPN":"君とフレデリカはオペレーターの同期であり、とても仲のいい友人だったと。","ENG":"That you and Frederica were both operator colleagues and best friends.","TWN":"你和弗蕾德莉卡是同梯，而且還是很好的朋友。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"어째서 사령부 권한까지 동원해가며, 프레데리카를 전쟁터로 내몰았던 거지?","JPN":"なぜ司令部の権限を行使してまで、フレデリカを戦場に追いやったんだ？","ENG":"Why did you have to force Frederica to battle using the authority of the Operations Command?","TWN":"為何你不惜動用司令部的權限，也要將弗蕾德莉卡送上戰場呢？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이유는 간단해. 그렇게 해서라도 내가 널 독차지하고 싶었으니까.","JPN":"理由は簡単だ。そうしてでもアタシはあんたを独り占めしたかったから。","ENG":"The reason is simple. I wanted you for myself.","TWN":"答案很簡單，因為我不惜這麼做也要得到你！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"TWN":"　"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그래서, 이제 어쩔 셈이야?","JPN":"それで、これからどうするつもりだ？","ENG":"So, what are you going to do now?","TWN":"那你現在打算怎麼做？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"우주로 떠나야지.","JPN":"宇宙に旅立つ。","ENG":"I’m leaving for outer space.","TWN":"當然是去宇宙囉。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"실종된 플라잉몬테규 호를 구하러.","JPN":"失踪したフライング・モンタギュー号を救うために。","ENG":"To save the lost Flying Montague.","TWN":"去拯救失蹤的普拉因蒙太古號！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"당신이… 프레데리카를 구하겠다고?","JPN":"君が……フレデリカを救う？","ENG":"You’re saying you’re... going to save Frederica?","TWN":"你…要去救弗蕾德莉卡？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"그녀를 미워하고 있는 게 아니었어?","JPN":"彼女を恨んでいたんじゃないのか？","ENG":"But don’t you hate her?","TWN":"你不是討厭她嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"프레데리카는 아카데미 시절, 내가 유일하게 인정한 라이벌이었지.","JPN":"フレデリカはアカデミー時代、アタシが唯一認めたライバルだった。","ENG":"Frederica was my only rival when we were at the academy.","TWN":"弗蕾德莉卡是我在學院時期，唯一認可的對手。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그녀가 무릎 꿇는 건 내 앞이어야만 해. 적들의 앞이 아니라.","JPN":"彼女が跪くのは敵ではなくて、アタシであるべきなんだ。","ENG":"She should only kneel in front of me, not in front of the enemies.","TWN":"她不能向敵人屈膝，只能向我屈膝！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"고작 그런 이유로 마음을 바꿨다고?","JPN":"そんな理由で心を変えたのか？","ENG":"That’s what made you change your mind?","TWN":"你只是因為這樣就改變心意？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그리고 로미오, 내가 사랑하는 당신이 그녀의 생환을 원하고 있으니까.","JPN":"それにロミオ、アタシの愛するあんたが彼女の生還を望んでるから。","ENG":"And Romeo, my love, it’s you who want her back alive.","TWN":"另外一個原因就是你，羅密歐，因為我愛的你希望她能夠生還。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_MAN","text":{"KOREA":"정말이지… 역시 당신이란 사람답군.","JPN":"まったく……やはり君らしいな。","ENG":"I would say... You are so you.","TWN":"果然…很有你的作風。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_MAN","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말 감동적이네요. 유마가 저런 긴 대사를 읊을 수 있게 되다니.","JPN":"とても感動的ですね。ユマがあんなに長いセリフを言えるようになるとは。","ENG":"This is so touching. I never thought Yuma would be able to memorize long lines like that.","TWN":"真是太感人，那麼長的台詞，游馬竟然說得出來。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그야 저 감독이 파벨라 몫의 대사를 전부 판넬에 적어서 보여주고 있으니까.","JPN":"それは、あの監督がファヴェーラのセリフを全部カンペに書いて見せてあげてるからのう。","ENG":"It’s because the director’s showing all of Fabella’s lines on a panel.","TWN":"那是因為導演把帕貝拉的台詞都寫在大字報上吧！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"현장에서도 느끼는 거지만, 정말이지 훌륭한 각본이군요.","JPN":"現場でも思ってたのですが、まったく素晴らしい脚本です。","ENG":"I can really feel that it’s a perfect script.","TWN":"光是在現場就很有感覺，這真是個很棒的劇本呢！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 명감독이라 불릴 만합니다.","JPN":"さすがは名監督。","ENG":"No wonder he’s a great director.","TWN":"確實有資格被稱為名導演。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그래, 그리고 내일이 되면, 이젠 나도 명감독의 반열에 오르게 되겠지.","JPN":"ああ、そして明日になれば、妾も名監督になるであろう。","ENG":"Yes, and when tomorrow comes, I’ll also be one of the greatest directors.","TWN":"沒錯，明天一到，我也會加入名導演的行列囉！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네? 하지만 주인님께선 오늘 아무것도…","JPN":"はい？　しかし、ご主人様は今日何も……","ENG":"What? But Mistress, you didn’t do anything today...","TWN":"嗯？可是主人今天好像什麼也…"},"stage":{"bg":"FALL_PARK","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};